sys_script_email.script:
var mlt = new x_1880990_chain.MagicLinkToken();
 var base = gs.getProperty('glide.servlet.uri') + 'api/x_1880990_chain/chain_magic_link/';
 var proposalId = current.sys_id.toString();
 var buyerId = current.buyer.toString();

 var urlAccept = base + 'counter_accept?token=' + mlt.generate(proposalId, buyerId, 'counter_accept');
 var urlReject = base + 'counter_reject_by_buyer?token=' + mlt.generate(proposalId, buyerId, 'counter_reject');

 var btnStyle = 'display: inline-block; padding: 12px 24px; margin: 0 6px; color: white; text-decoration: none; border-radius: 4px; font-weight: bold;';

 template.print(
     '<div style="text-align: center; margin: 32px 0;">' +
     '<a href="' + urlAccept + '" style="' + btnStyle + ' background: #27ae60;">Aceitar contraproposta</a>' +
     '<a href="' + urlReject + '" style="' + btnStyle + ' background: #c0392b;">Recusar</a>' +
     '</div>' 
 );
